const route = NjTransit.newBusAdvisory.RouteAndTime;
if (!route || !(typeof route === 'string')) {
  Sms.sendMeText.skip('No RouteAndTime provided');
} else if (route.indexOf('Sapri-Fisciano') < 0) {
  Sms.sendMeText.skip('Route does not match "Sapri-Fisciano"');
} else if (!NjTransit.newBusAdvisory.Link || NjTransit.newBusAdvisory.Link === '') {
  Sms.sendMeText.setMessage(`Alert for Curcio train on route: ${route}`);
} else {
  const baseTime = Meta.currentUserTime;
  // Parse the RouteAndTime to a moment object
  const parsedTime = Meta.parseMomentInZone(NjTransit.newBusAdvisory.RouteAndTime, 'America/New_York');
  if (!parsedTime) {
    Sms.sendMeText.skip('Failed to parse RouteAndTime as moment');
  } else {
    const diffMinutes = baseTime.diff(parsedTime, 'minutes');
    // If the advisory is for Curcio and not after base time or with delay, skip action
    if (route !== 'Curcio' || diffMinutes > 0) {
      Sms.sendMeText.skip('Not a Curcio train after base time or with delay');
    } else {
      // Compose the message including link and route info
      const message = `Alert for Curcio train on route: ${route} - Advisory Link: ${NjTransit.newBusAdvisory.Link}`;
      Sms.sendMeText.setMessage(message);
    }
  }
}
