} else if (NjTransit.newBusAdvisory.RouteAndTime !== 'Fisciano Università - Salerno') {
  Sms.sendMeText.skip();
} else {
  const timeMatch = advisoryContent.match(/(\d+:\d+) - (\d+:\d+)/);
  if (!timeMatch || (timeMatch[1] !== '09:00' && timeMatch[2] !== '11:00')) {
    Sms.sendMeText.skip();
  } else {
    const route = advisoryContent.match(/^([^-]+)/)?.[1].trim() || '';
    const hourMinute = advisoryContent.match(/\d+:\d+/);
    if (!hourMinute) {
      Sms.sendMeText.skip();
    } else {
      const message = `[Tratta] delle ore ${hourMinute} è in ritardo. \n ${NjTransit.newBusAdvisory.Link}`;
      Sms.sendMeText.setMessage(message);
    }
  }
}

