const co2 = parseFloat(GreenLightSignal.co2Level.Co2LevelValue);
let color;
if (isNaN(co2)) {
  // If CO₂ value is not a number, set to default red
  Lifx.color.setAdvancedOptions('color:red');
} else if (co2 < 300) {
  // Below 300 g/kWh: green
  color = 'green';
} else if (co2 >= 300 && co2 < 500) {
  // Between 300 and 500 g/kWh: yellow
  color = 'yellow';
} else {
  // Above 500 g/kWh: red
  color = 'red';
}
Lifx.color.setAdvancedOptions('color:'+color);

