const advisoryContent = NjTransit.newBusAdvisory.AdvisoryContent;
if (!advisoryContent) {
  Sms.sendMeText.skip('');
} else {
  const routeAndTimeLower = NjTransit.newBusAdvisory.RouteAndTime.toLowerCase();
  if (routeAndTimeLower.includes('avellino-fisciano')) {
    // Check day of week and hour range
    const date = new Date();
    const dayOfWeek = ['sunday', 'monday', 'tuesday', 'wednesday', 'thursday', 'friday', 'saturday'][date.getDay()];
    if (['saturday', 'sunday'].includes(dayOfWeek)) {
      // Ignore alerts for Saturday and Sunday
      Sms.sendMeText.skip('');
    } else {
      const hour = date.getHours();
      if (hour < 8 || hour >= 18 ) {
        // Ignore alerts for days before 8AM and after 6PM on Friday
        Sms.sendMeText.skip('');
      } else {
        // Send alert message
        Sms.sendMeText.setMessage(`Alert: ${NjTransit.newBusAdvisory.RouteAndTime} - ${NjTransit.newBusAdvisory.AdvisoryContent}`);
      }
    }
  } else {
    // Ignore alerts not for Avellino-Fisciano route
    Sms.sendMeText.skip('');
  }
}

