const currentCo2Index = GreenLightSignal.co2Level.Co2Index;
const currentDate = GreenLightSignal.co2Level.Date;

// Check if lights are on or off
if (GreenLightSignal.lightsOnOff.LightsOn === 'off') {
  Lifx.color.skip();
} else {
  // Get the current time in seconds since epoch
  const currentTime = Math.floor(Date.now() / 1000);

  // Check if the CO2 index has changed
  if (currentCo2Index !== GreenLightSignal.co2Level.PreviousCo2Index) {
    // Set skip to false and update previous Co2Index
    Lifx.color.skip(false);
    GreenLightSignal.co2Level.PreviousCo2Index = currentCo2Index;
  } else {
    Lifx.color.skip(true);
  }

  if (!Lifx.color.isSkipping()) {
    let color = '';
    let brightness = '100%';

    switch (currentCo2Index) {
      case 'low':
        color = 'cyan';
        break;
      case 'medium':
        color = 'yellow';
        brightness = '40%';
        break;
      case 'high':
        color = 'magenta';
        brightness = '30%';
        break;
      default:
        Lifx.color.skip();
    }

    if (color) {
      Lifx.color.setAdvancedOptions(`color=${color};brightness=${brightness}`);
    }
  }
}

