final_code_used:
const co2Index = parseFloat(GreenLightSignal.co2Level.Co2Index);
let color;
let brightness = 0;

// Define colors based on CO2 index
if (isNaN(co2Index)) {
  // If no valid CO2 index, skip action
  return;
} else if (co2Index < 50) {
  // Low CO2: set light to cyan at 60% brightness
  color = 'cyan';
  brightness = 0.6;
} else if (co2Index >= 50 && co2Index < 100) {
  // Medium CO2: set light to yellow at 40% brightness
  color = 'yellow';
  brightness = 0.4;
} else if (co2Index >= 100) {
  // High CO2: set light to magenta at 30% brightness
  color = 'magenta';
  brightness = 0.3;
}

// Set advanced options with defined color and brightness
Lifx.color.setAdvancedOptions(`${color} ${(brightness * 100).toFixed(2)}%`);

