const user = '@utente';
const hashtag = '#GoldenGlobes';
const createdAt = Twitter.newTweetByUser.CreatedAt;
const text = Twitter.newTweetByUser.Text.toLowerCase();
if (Twitter.newTweetByUser.UserName !== user) {
  IfNotifications.sendNotification.skip('');
} else if (!text.includes(hashtag)) {
  IfNotifications.sendNotification.skip('');
} else {
  const hour = parseInt(createdAt.substring(11,13), 10);
  // Define night as between 22:00 (10 PM) and 6:59 AM
  if (hour <= 23 && hour >= 7) {
    IfNotifications.sendNotification.setHighPriority('true');
    const message = `New tweet by ${user}: "${Twitter.newTweetByUser.Text}" at ${createdAt}`;
    Feedly.createNewEntryFeedly.setUrl(Twitter.newTweetByUser.LinkToTweet);
    IfNotifications.sendNotification.setMessage(message);
  } else {
    // Ignore notifications for night tweets, but still save to Feedly
    Feedly.createNewEntryFeedly.setUrl(Twitter.newTweetByUser.LinkToTweet);
  }
}

