const user = '@user';
const magicRomeKeywords = ['magic', 'roma'];
const silentHoursStart = 20; // 8 PM
const silentHoursEnd = 6; // 6 AM

// Parse CreatedAt to Date object and extract hour
const createdAtDate = new Date(Twitter.newTweetByUser.CreatedAt);
const createdAtHour = createdAtDate.getHours();

// Check if current time is within silent hours
const now = Meta.currentUserTime;
const currentHour = now.hour();
if (createdAtHour >= silentHoursStart || createdAtHour < silentHoursEnd) {
  // Silent hours, do not send notification
} else if (!Twitter.newTweetByUser.Text.toLowerCase().includes(user)) {
  // Not by user or no text, do not send notification
} else if (magicRomeKeywords.some(keyword => Twitter.newTweetByUser.Text.toLowerCase().includes(keyword))) {
  Feedly.addNewEntryFeedly.setUrl(Twitter.newTweetByUser.LinkToTweet);
} else {
  IfNotifications.sendNotification.setMessage('New tweet from ' + Twitter.newTweetByUser.UserName + ': "' + Twitter.newTweetByUser.Text + '"');
}
```
This code assumes that the silent hours are between 8 PM and 6 AM, inclusive. It checks if the current time is within these hours; if so, it does not send a notification. If the tweet was by user but outside of silent hours, it sends a notification with the text of the tweet. If the tweet contains any keyword from `magicRomeKeywords` array and no mention of 'silence', it saves the link to the tweet on Feedly.

