const advisoryContent = NjTransit.newBusAdvisory.AdvisoryContent;
if (!advisoryContent) {
  Sms.sendMeText.skip('No advisory content found!');
} else {
  const routeAndTimeMatch = advisoryContent.match(/Route: (.*?)<br>/);
  if (!routeAndTimeMatch || !routeAndTimeMatch[1]) {
    Sms.sendMeText.skip('No route and time found!');
  } else {
    const [route, time] = routeAndTimeMatch[1].split('<br>').map(s => s.trim());
    if (!time) {
      Sms.sendMeText.skip('No time found!');
    } else {
      // Check if the trip is for Fisciano Università and Salerno, and the hour is between 9:00 and 11:00
      const routeLower = route.toLowerCase();
      if (!routeLower.includes('fisciano universita') || !routeLower.includes('salerno')) {
        Sms.sendMeText.skip('Not for Fisciano Università or Salerno!');
      } else {
        const hour = parseInt(time.split(':')[0], 10);
        if (isNaN(hour) || hour < 9 || hour > 11) {
          Sms.sendMeText.skip('Not in time range!');
        } else {
          const message = `${route} leaves at ${time}.\n${NjTransit.newBusAdvisory.Link}`;
          Sms.sendMeText.setMessage(message);
        }
      }
    }
  }
}

