final_code_used:
const userName = Twitter.newTweetByUser.UserName;
if (userName !== '@unieuro') {
  IfNotifications.skip();
} else {
  const tweetTextLowerCase = Twitter.newTweetByUser.Text.toLowerCase();
  if (!tweetTextLowerCase.includes('frullatori')) {
    IfNotifications.skip();
  } else {
    // Extract URL from TweetEmbedCode (assuming it's the first link in the tweet)
    const embedCode = Twitter.newTweetByUser.TweetEmbedCode;
    const urlRegex = /<a href="([^"]+)" rel="nofollow"/i;
    const match = embedCode.match(urlRegex);
    if (!match || !match[1]) {
      IfNotifications.skip();
    } else {
      Feedly.createNewEntryFeedly.setUrl(match[1]);
      // Compose notification message with tweet content and user info
      const createdAt = Twitter.newTweetByUser.CreatedAt;
      const formattedDate = Meta.currentUserTime.clone().tz('Europe/Rome').format('YYYY-MM-DD HH:mm');
      const message = `Nuova offerta pubblicata da ${userName} il ${formattedDate}:\n${Twitter.newTweetByUser.Text}\nURL: ${match[1]}`;
      IfNotifications.sendNotification.setMessage(message);
    }
  }
}
// Check if current time is outside of allowed hours (21:00 to 8:00)
const hour = Meta.currentUserTime.hour();
if (hour >= 21 || hour < 8) {
  IfNotifications.skip();
} else {
  // Set high priority notification if time is within allowed hours
  IfNotifications.sendNotification.setHighPriority('true');
}

